\frac{1}{1 - \tan^2 x} &= \frac{1}{\frac{\cos^2 x}{\sin^2 x} - 1} \\
&= \frac{1}{\frac{\cos^2 x - \sin^2 x}{\sin^2 x}} \\
&= \frac{\sin^2 x}{\cos^2 x - \sin^2 x} \\
&= \frac{\sin^2 x}{\cos 2x}.\end{align*}
Similarly,
\begin{align*}
\frac{1}{1 - \cot^2 x} &= \frac{1}{\frac{\sin^2 x}{\cos^2 x} - 1} \\
&= \frac{1}{\frac{\sin^2 x - \cos^2 x}{\cos^2 x}} \\
&= \frac{\cos^2 x}{\sin^2 x - \cos^2 x} \\
&= \frac{\cos^2 x}{-\cos 2x}.\end{align*}
